final:
module branch_predictor(  
    input clk,  
    input reset,  
    input taken,  
    output reg prediction  
);  
    reg [1:0] predictor_state;  

    always @(posedge clk or posedge reset) begin  
        if (reset)  
            predictor_state <= 2'b00;  
        else begin  
            if (taken)  
                predictor_state <= (predictor_state == 2'b11) ? 2'b11 : predictor_state + 1;  
            else  
                predictor_state <= (predictor_state == 2'b00) ? 2'b00 : predictor_state - 1;  
        end  
    end  

    always @(*) begin  
        prediction = (predictor_state[1] == 1'b1);  
    end  
endmodule
